initScript:
await ManagerApi.ready();
const fileApiBase = ManagerApi.getBase() + '/file';
const dirApiBase = ManagerApi.getBase() + '/dir';
const siteApiBase = ManagerApi.getBase() + '/site';
const workspaceRoot = (await utils.postForm(siteApiBase + '/get_root.php', {})).trim().replace(/\/$/, '');
const baseDirAbs = workspaceRoot + '/.temp';
return {
  workspaceRoot,
  baseDirAbs,
  absDirName: 'abs-dir',
  absDirRenamed: 'abs-dir-renamed',
  absFileName: 'abs-file.txt',
  absFileRenamed: 'abs-file-renamed.txt',
  createDirUrl: dirApiBase + '/create_dir.php',
  scanDirUrl: dirApiBase + '/scan_dir.php',
  renameDirUrl: dirApiBase + '/rename_dir.php',
  deleteDirUrl: dirApiBase + '/delete_dir.php',
  createFileUrl: fileApiBase + '/create_file.php',
  scanFileUrl: fileApiBase + '/scan_file.php',
  writeFileUrl: fileApiBase + '/write_file.php',
  readFileUrl: fileApiBase + '/read_file.php',
  renameFileUrl: fileApiBase + '/rename_file.php',
  deleteFileUrl: fileApiBase + '/delete_file.php',
  message: 'init done: ' + baseDirAbs
};

finallyScript:
const fileNames = ['abs-file.txt', 'abs-file-renamed.txt'];
const dirNames = ['abs-dir', 'abs-dir-renamed'];
for (const f of fileNames) {
  try { await utils.postForm(deleteFileUrl, { path: baseDirAbs + '/' + f }); } catch (_) {}
}
for (const d of dirNames) {
  try { await utils.postForm(deleteDirUrl, { path: baseDirAbs + '/' + d }); } catch (_) {}
}
return { message: 'cleanup done' };

tests.scriptText:
const dt = await utils.postForm(createDirUrl, { dir: baseDirAbs, name: absDirName });
const dm = dt.match(/\[(.+?)\/\]/);
assert(dm && dm[1], 'create_dir: parse fail');
const ft = await utils.postForm(createFileUrl, { dir: baseDirAbs, name: absFileName });
const fm = ft.match(/\[(.+?)\]/);
assert(fm && fm[1], 'create_file: parse fail');
return { dirPath: dm[1], filePath: fm[1], message: 'created dir + file' };

await utils.postForm(writeFileUrl, { path: filePath, content: 'absolute test content' });
const text = await utils.postForm(readFileUrl, { path: filePath });
assert(text.includes('absolute test content'), 'write_read: content mismatch');
return { message: 'write/read ok' };

const dirs = JSON.parse((await utils.postForm(scanDirUrl, { path: baseDirAbs })) || '[]');
const files = JSON.parse((await utils.postForm(scanFileUrl, { path: baseDirAbs })) || '[]');
assert(Array.isArray(dirs), 'scan: dirs not array');
assert(Array.isArray(files), 'scan: files not array');
assert(dirs.includes(absDirName), 'scan: dir missing');
assert(files.includes(absFileName), 'scan: file missing');
return { message: 'scan ok' };

const dt = await utils.postForm(renameDirUrl, { path: dirPath + '/', name: absDirRenamed });
const dm = dt.match(/to \[(.+?)\/\]/);
assert(dm && dm[1], 'rename dir: parse fail');
const ft = await utils.postForm(renameFileUrl, { path: filePath, name: absFileRenamed });
const fm = ft.match(/to \[(.+?)\]/);
assert(fm && fm[1], 'rename file: parse fail');
return { dirPath: dm[1], filePath: fm[1], message: 'renamed both' };

await utils.postForm(deleteFileUrl, { path: filePath });
await utils.postForm(deleteDirUrl, { path: dirPath + '/' });
const dirs = JSON.parse((await utils.postForm(scanDirUrl, { path: baseDirAbs })) || '[]');
const files = JSON.parse((await utils.postForm(scanFileUrl, { path: baseDirAbs })) || '[]');
assert(Array.isArray(dirs), 'delete verify: dirs not array');
assert(Array.isArray(files), 'delete verify: files not array');
assert(!dirs.includes(utils.basename(dirPath)), 'delete verify: dir still exists');
assert(!files.includes(utils.basename(filePath)), 'delete verify: file still exists');
return { message: 'deleted + verified' };
